              {/* Aviso de segurança */}
              <Alert severity="info" sx={{ mt: 2, mb: 2, backgroundColor: 'rgba(0, 0, 0, 0.6)', color: '#C0C0C0', border: '1px solid rgba(192, 192, 192, 0.3)' }}>
                <Typography variant="caption" sx={{ color: '#C0C0C0' }}>
                  🔒 Suas credenciais da API são criptografadas com AES-256 e armazenadas com segurança.
                  Nunca compartilhe suas chaves de API com terceiros.
                </Typography>
              </Alert>

              {/* Botões de ação */}
              <Box sx={{ mt: 3, mb: 2 }}>
                <Button
                  onClick={(e) => {
                    // CRÍTICO: Não é mais um submit, é apenas um clique
                    e.preventDefault();
                    e.stopPropagation();
                    handleSubmit(e);
                  }}
                  fullWidth
                  variant="contained"
                  disabled={loading || !isPasswordValid() || (!hasPaymentAccess && !inviteCodeVerified)}
                  sx={{
                    py: 1.5,
                    fontSize: '1rem',
                    fontWeight: 'bold',
                    background: (hasPaymentAccess || inviteCodeVerified) ? 'rgba(0, 0, 0, 0.8)' : 'rgba(0, 0, 0, 0.3)',
                    border: (hasPaymentAccess || inviteCodeVerified) ? '1px solid rgba(192, 192, 192, 0.3)' : '1px solid rgba(192, 192, 192, 0.1)',
                    color: (hasPaymentAccess || inviteCodeVerified) ? '#C0C0C0' : 'rgba(192, 192, 192, 0.3)',
                    '&:hover': {
                      background: (hasPaymentAccess || inviteCodeVerified) ? 'rgba(0, 0, 0, 0.9)' : 'rgba(0, 0, 0, 0.3)',
                      border: (hasPaymentAccess || inviteCodeVerified) ? '1px solid #C0C0C0' : '1px solid rgba(192, 192, 192, 0.1)',
                    },
                    '&:disabled': {
                      background: 'rgba(0, 0, 0, 0.3)',
                      border: '1px solid rgba(192, 192, 192, 0.1)',
                      color: 'rgba(192, 192, 192, 0.3)'
                    },
                  }}
                >
                  {loading ? (
                    <CircularProgress size={24} sx={{ color: '#C0C0C0' }} />
                  ) : (hasPaymentAccess || inviteCodeVerified) ? (
                    'Criar Conta'
                  ) : (
                    'Pagamento Necessário'
                  )}
                </Button>

                {/* Botão para limpar erro - só aparece quando há erro */}
                {error && (
                  <Button
                    fullWidth
                    variant="outlined"
                    onClick={() => {
                      setError('');
                      setErrorPersistent(false);
                      toast.dismiss(); // Fechar todos os toasts
                    }}
                    sx={{
                      mt: 1,
                      py: 1.5,
                      fontSize: errorPersistent ? '1rem' : '0.9rem',
                      fontWeight: 'bold',
                      background: errorPersistent ? 'rgba(255, 107, 107, 0.2)' : 'rgba(0, 0, 0, 0.3)',
                      border: errorPersistent ? '2px solid #ff6b6b' : '1px solid rgba(255, 107, 107, 0.5)',
                      color: '#ff6b6b',
                      animation: errorPersistent ? 'pulse 2s infinite' : 'none',
                      '&:hover': {
                        background: 'rgba(255, 107, 107, 0.3)',
                        border: '2px solid #ff6b6b',
                      }
                    }}
                  >
                    {errorPersistent ? '🚨 CLIQUE AQUI PARA LIMPAR O ERRO 🚨' : '✕ Limpar Mensagem de Erro'}
                  </Button>
                )}
              </Box>

              {/* Link para login */}
              <Box sx={{ textAlign: 'center', mt: 2 }}>
                <Typography variant="body2" sx={{ color: '#C0C0C0' }}>
                  Já tem uma conta?{' '}
                  <Link
                    component={RouterLink}
                    to="/login"
                    sx={{
                      color: '#C0C0C0',
                      textDecoration: 'underline',
                      fontWeight: 'bold',
                      '&:hover': {
                        textDecoration: 'underline',
                      },
                    }}
                  >
                    Faça login
                  </Link>
                </Typography>
              </Box>
            </Box>
          )}
        </Paper>
      </Box>
    </Container>

    {/* Modal de Erro Persistente */}
    <Dialog
      open={errorModalOpen}
      onClose={() => {}} // Desabilitar fechar clicando fora
      disableEscapeKeyDown // Desabilitar fechar com ESC
      hideBackdrop={false} // Manter backdrop escuro
      maxWidth="md"
      fullWidth
      PaperProps={{
        sx: {
          background: 'rgba(0, 0, 0, 0.95)',
          border: '3px solid #ff6b6b',
          borderRadius: 3,
          boxShadow: '0 0 30px rgba(255, 107, 107, 0.5)',
          position: 'relative',
          zIndex: 9999
        }
      }}
      BackdropProps={{
        sx: {
          backgroundColor: 'rgba(0, 0, 0, 0.8)', // Backdrop mais escuro
          zIndex: 9998
        }
      }}
    >
      <DialogTitle
        sx={{
          backgroundColor: 'rgba(255, 107, 107, 0.2)',
          color: '#ff6b6b',
          fontWeight: 'bold',
          fontSize: '1.5rem',
          textAlign: 'center',
          borderBottom: '2px solid #ff6b6b',
          py: 2
        }}
      >
        {errorModalTitle}
      </DialogTitle>

      <DialogContent
        sx={{
          backgroundColor: 'rgba(0, 0, 0, 0.8)',
          color: '#ffffff',
          fontSize: '1.1rem',
          lineHeight: 1.6,
          py: 3,
          px: 3
        }}
      >
        <Typography
          variant="body1"
          sx={{
            whiteSpace: 'pre-line',
            color: '#ffffff',
            fontSize: '1rem',
            lineHeight: 1.8,
            mb: 3
          }}
        >
          {errorModalMessage}
        </Typography>

        <Box
          sx={{
            backgroundColor: 'rgba(255, 107, 107, 0.15)',
            border: '1px solid rgba(255, 107, 107, 0.5)',
            borderRadius: 2,
            p: 2,
            mt: 3
          }}
        >
          <Typography
            variant="body2"
            sx={{
              color: '#ffcccc',
              fontSize: '0.9rem',
              fontWeight: 'bold',
              textAlign: 'center'
            }}
          >
            ⚠️ ESCOLHA UMA OPÇÃO ABAIXO PARA CONTINUAR ⚠️
          </Typography>
        </Box>
      </DialogContent>

      <DialogActions
        sx={{
          backgroundColor: 'rgba(255, 107, 107, 0.1)',
          borderTop: '1px solid #ff6b6b',
          p: 3,
          justifyContent: 'space-between',
          flexDirection: { xs: 'column', sm: 'row' },
          gap: 2
        }}
      >
        <Button
          onClick={closeErrorModal}
          variant="outlined"
          sx={{
            backgroundColor: 'transparent',
            color: '#ff6b6b',
            borderColor: '#ff6b6b',
            fontWeight: 'bold',
            fontSize: '1rem',
            px: 3,
            py: 1.5,
            minWidth: '200px',
            '&:hover': {
              backgroundColor: 'rgba(255, 107, 107, 0.1)',
              borderColor: '#ff5252'
            }
          }}
        >
          🔄 TENTAR NOVAMENTE
        </Button>

        <Button
          onClick={() => {
            closeErrorModal();
            navigate('/login');
          }}
          variant="contained"
          sx={{
            backgroundColor: '#ff6b6b',
            color: '#ffffff',
            fontWeight: 'bold',
            fontSize: '1rem',
            px: 3,
            py: 1.5,
            minWidth: '200px',
            '&:hover': {
              backgroundColor: '#ff5252',
              boxShadow: '0 0 15px rgba(255, 107, 107, 0.8)'
            }
          }}
        >
          ← VOLTAR AO LOGIN
        </Button>
      </DialogActions>
    </Dialog>
    </>
  );
};

export default Register;
